/**
 * Task Scheduler
 *
 * Manages the ready queue and tracks in-progress tasks.
 * Determines which tasks can run next based on dependencies.
 */

import type { Feature, Task, TaskStatus } from '../types.js';
import { DependencyGraph } from '../graph/DependencyGraph.js';
import { CriticalPath } from '../graph/CriticalPath.js';
import { PriorityQueue } from './PriorityQueue.js';

export class TaskScheduler {
  private tasks: Map<string, Task> = new Map();
  private readyQueue: PriorityQueue<string> = new PriorityQueue();
  private inProgress: Set<string> = new Set();
  private criticalPath: CriticalPath;

  constructor(
    private graph: DependencyGraph,
    private maxConcurrent: number = 3
  ) {
    this.criticalPath = new CriticalPath(graph);
    this.initializeTasks();
    this.refreshReadyQueue();
  }

  private initializeTasks(): void {
    for (const feature of this.graph.getAllFeatures()) {
      this.tasks.set(feature.id, {
        feature,
        status: feature.passes ? 'completed' : 'pending',
      });
    }
  }

  /**
   * Refresh the ready queue based on current state
   */
  refreshReadyQueue(): void {
    this.readyQueue.clear();

    const ready = this.graph.getReadyTasks();
    for (const feature of ready) {
      if (
        !this.inProgress.has(feature.id) &&
        this.getTaskStatus(feature.id) === 'pending'
      ) {
        const priority = -this.criticalPath.getPriorityScore(feature.id);
        this.readyQueue.enqueue(feature.id, priority);
      }
    }
  }

  /**
   * Get the next tasks to run (up to available slots)
   */
  getNextTasks(): Feature[] {
    const available = this.maxConcurrent - this.inProgress.size;
    if (available <= 0) return [];

    const tasks: Feature[] = [];

    for (let i = 0; i < available && !this.readyQueue.isEmpty(); i++) {
      const taskId = this.readyQueue.dequeue();
      if (taskId) {
        const feature = this.graph.getFeature(taskId);
        if (feature) {
          tasks.push(feature);
          this.inProgress.add(taskId);
        }
      }
    }

    return tasks;
  }

  /**
   * Mark a task as running
   */
  startTask(taskId: string, agentId: string): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = 'running';
      task.startedAt = new Date();
      task.agentId = agentId;
      this.inProgress.add(taskId);
    }
  }

  /**
   * Mark a task as completed
   */
  completeTask(taskId: string): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = 'completed';
      task.completedAt = new Date();
      task.feature.passes = true;
      this.inProgress.delete(taskId);
      this.refreshReadyQueue();
    }
  }

  /**
   * Mark a task as failed
   */
  failTask(taskId: string, error: string): void {
    const task = this.tasks.get(taskId);
    if (task) {
      task.status = 'failed';
      task.error = error;
      task.completedAt = new Date();
      this.inProgress.delete(taskId);
    }
  }

  /**
   * Get task status
   */
  getTaskStatus(taskId: string): TaskStatus {
    return this.tasks.get(taskId)?.status || 'pending';
  }

  /**
   * Get task details
   */
  getTask(taskId: string): Task | undefined {
    return this.tasks.get(taskId);
  }

  /**
   * Get number of running tasks
   */
  getRunningCount(): number {
    return this.inProgress.size;
  }

  /**
   * Get all in-progress task IDs
   */
  getInProgressTasks(): string[] {
    return [...this.inProgress];
  }

  /**
   * Check if all tasks are complete
   */
  isComplete(): boolean {
    return [...this.tasks.values()].every(
      (t) => t.status === 'completed' || t.status === 'failed'
    );
  }

  /**
   * Get summary statistics
   */
  getSummary(): { pending: number; running: number; completed: number; failed: number } {
    let pending = 0,
      running = 0,
      completed = 0,
      failed = 0;

    for (const task of this.tasks.values()) {
      switch (task.status) {
        case 'pending':
        case 'ready':
          pending++;
          break;
        case 'running':
          running++;
          break;
        case 'completed':
          completed++;
          break;
        case 'failed':
          failed++;
          break;
      }
    }

    return { pending, running, completed, failed };
  }
}

