     1→/**
     2→ * Claude Agent
     3→ *
     4→ * Wrapper for spawning and managing a single Claude CLI process.
     5→ */
     6→
     7→import { spawn, type ChildProcess } from 'node:child_process';
     8→import { EventEmitter } from 'node:events';
     9→import type { Feature, ModelType } from '../types.js';
    10→
    11→export interface AgentOptions {
    12→  model: ModelType;
    13→  maxBudget?: number;
    14→  timeout?: number;
    15→  cwd?: string;
    16→}
    17→
    18→export interface AgentResult {
    19→  success: boolean;
    20→  output: string;
    21→  error?: string;
    22→  duration: number;
    23→}
    24→
    25→export class ClaudeAgent extends EventEmitter {
    26→  readonly id: string;
    27→  private process: ChildProcess | null = null;
    28→  private output: string[] = [];
    29→  private errorOutput: string[] = [];
    30→  private startTime: number = 0;
    31→
    32→  constructor(
    33→    id: string,
    34→    private options: AgentOptions
    35→  ) {
    36→    super();
    37→    this.id = id;
    38→  }
    39→
    40→  /**
    41→   * Execute a feature task
    42→   */
    43→  async executeFeature(feature: Feature): Promise<AgentResult> {
    44→    const prompt = this.buildPrompt(feature);
    45→    return this.execute(prompt);
    46→  }
    47→
    48→  /**
    49→   * Execute a raw prompt
    50→   */
    51→  async execute(prompt: string): Promise<AgentResult> {
    52→    return new Promise((resolve) => {
    53→      this.startTime = Date.now();
    54→      this.output = [];
    55→      this.errorOutput = [];
    56→
    57→      const args = this.buildArgs(prompt);
    58→
    59→      this.process = spawn('claude', args, {
    60→        cwd: this.options.cwd || process.cwd(),
    61→        shell: true,
    62→        stdio: ['inherit', 'pipe', 'pipe'],
    63→      });
    64→
    65→      const timeout = this.options.timeout || 10 * 60 * 1000; // 10 min default
    66→      const timeoutId = setTimeout(() => {
    67→        this.kill('Timeout exceeded');
    68→      }, timeout);
    69→
    70→      this.process.stdout?.on('data', (data: Buffer) => {
    71→        const text = data.toString();
    72→        this.output.push(text);
    73→        this.emit('output', text);
    74→      });
    75→
    76→      this.process.stderr?.on('data', (data: Buffer) => {
    77→        const text = data.toString();
    78→        this.errorOutput.push(text);
    79→        this.emit('error', text);
    80→      });
    81→
    82→      this.process.on('error', (err) => {
    83→        clearTimeout(timeoutId);
    84→        resolve({
    85→          success: false,
    86→          output: this.output.join(''),
    87→          error: err.message,
    88→          duration: Date.now() - this.startTime,
    89→        });
    90→      });
    91→
    92→      this.process.on('close', (code) => {
    93→        clearTimeout(timeoutId);
    94→        resolve({
    95→          success: code === 0,
    96→          output: this.output.join(''),
    97→          error: code !== 0 ? this.errorOutput.join('') : undefined,
    98→          duration: Date.now() - this.startTime,
    99→        });
   100→      });
   101→    });
   102→  }
   103→
   104→  /**
   105→   * Build command line arguments for claude CLI
   106→   *
   107→   * Key flags for context isolation:
   108→   * - `-p` (print mode): Non-interactive, exits after completion
   109→   * - `--no-session-persistence`: Does NOT save to disk, cannot be resumed
   110→   * - Each execution is a fresh context with no memory of previous tasks
   111→   */
   112→  private buildArgs(prompt: string): string[] {
   113→    const args = [
   114→      '-p',                        // Print mode (non-interactive)
   115→      '--no-session-persistence',  // Don't persist session - clean context every time
   116→    ];
   117→
   118→    if (this.options.model) {
   119→      args.push('--model', this.options.model);
   120→    }
   121→
   122→    if (this.options.maxBudget) {
   123→      args.push('--max-budget-usd', String(this.options.maxBudget));
   124→    }
   125→
   126→    args.push(JSON.stringify(prompt));
   127→
   128→    return args;
   129→  }
   130→
   131→  /**
   132→   * Build prompt for a feature
   133→   *
   134→   * Since each agent starts with a fresh context (no memory of previous sessions),
   135→   * the prompt must be self-contained with all necessary instructions.
   136→   */
   137→  private buildPrompt(feature: Feature): string {
   138→    return `# Task Assignment: ${feature.id}
   139→
   140→## Your Mission
   141→Complete feature **${feature.id}**: ${feature.description}
   142→
   143→## Steps to Complete
   144→${feature.steps.map((s, i) => `${i + 1}. ${s}`).join('\n')}
   145→
   146→${feature.notes ? `## Additional Notes\n${feature.notes}\n` : ''}
   147→
   148→## Harness Protocol (MANDATORY)
   149→
   150→You are part of an automated harness system. Each task runs in an **isolated context** with no memory of previous sessions.
   151→
   152→### Before Starting
   153→1. **READ** \`progress.txt\` to understand current project state
   154→2. **READ** \`CLAUDE.md\` for project-specific instructions
   155→3. **READ** \`features.json\` to understand your task and its dependencies
   156→
   157→### During Implementation
   158→4. Implement the feature following the steps above
   159→5. Test your implementation
   160→6. Keep changes focused on this feature only
   161→
