     1→/**
     2→ * State Manager
     3→ *
     4→ * Manages atomic updates to features.json and provides
     5→ * state snapshots for recovery.
     6→ */
     7→
     8→import { readFileSync, writeFileSync, existsSync, copyFileSync } from 'node:fs';
     9→import { join, dirname } from 'node:path';
    10→import type { HarnessConfig, Feature } from '../types.js';
    11→import { FileLock } from './FileLock.js';
    12→
    13→export class StateManager {
    14→  private lock: FileLock = new FileLock();
    15→  private snapshotDir: string;
    16→
    17→  constructor(
    18→    private featuresPath: string,
    19→    snapshotDir?: string
    20→  ) {
    21→    this.snapshotDir = snapshotDir || dirname(featuresPath);
    22→  }
    23→
    24→  /**
    25→   * Load the current harness config
    26→   */
    27→  load(): HarnessConfig {
    28→    const content = readFileSync(this.featuresPath, 'utf-8');
    29→    return JSON.parse(content);
    30→  }
    31→
    32→  /**
    33→   * Save the harness config atomically
    34→   */
    35→  async save(config: HarnessConfig): Promise<void> {
    36→    await this.lock.withLock(this.featuresPath, async () => {
    37→      const content = JSON.stringify(config, null, 2);
    38→      writeFileSync(this.featuresPath, content, 'utf-8');
    39→    });
    40→  }
    41→
    42→  /**
    43→   * Update a specific feature's status
    44→   */
    45→  async updateFeature(
    46→    featureId: string,
    47→    updates: Partial<Feature>
    48→  ): Promise<void> {
    49→    await this.lock.withLock(this.featuresPath, async () => {
    50→      const config = this.load();
    51→      const feature = config.features.find((f) => f.id === featureId);
    52→
    53→      if (!feature) {
    54→        throw new Error(`Feature not found: ${featureId}`);
    55→      }
    56→
    57→      Object.assign(feature, updates);
    58→      config.lastUpdated = new Date().toISOString().split('T')[0];
    59→
    60→      const content = JSON.stringify(config, null, 2);
    61→      writeFileSync(this.featuresPath, content, 'utf-8');
    62→    });
    63→  }
    64→
    65→  /**
    66→   * Mark a feature as complete
    67→   */
    68→  async markComplete(featureId: string): Promise<void> {
    69→    await this.updateFeature(featureId, { passes: true });
    70→  }
    71→
    72→  /**
    73→   * Create a snapshot of current state
    74→   */
    75→  createSnapshot(name?: string): string {
    76→    const timestamp = Date.now();
    77→    const snapshotName = name || `snapshot-${timestamp}`;
    78→    const snapshotPath = join(this.snapshotDir, `${snapshotName}.json`);
    79→
    80→    copyFileSync(this.featuresPath, snapshotPath);
    81→
    82→    return snapshotPath;
    83→  }
    84→
    85→  /**
    86→   * Restore from a snapshot
    87→   */
    88→  async restoreSnapshot(snapshotPath: string): Promise<void> {
    89→    if (!existsSync(snapshotPath)) {
    90→      throw new Error(`Snapshot not found: ${snapshotPath}`);
    91→    }
    92→
    93→    await this.lock.withLock(this.featuresPath, async () => {
    94→      copyFileSync(snapshotPath, this.featuresPath);
    95→    });
    96→  }
    97→
    98→  /**
    99→   * Get progress summary
