     1→/**
     2→ * Real-time Progress Dashboard
     3→ *
     4→ * Terminal UI that displays:
     5→ * - Agent status (busy/idle)
     6→ * - Progress bars per feature
     7→ * - Cost tracking (estimated API usage)
     8→ * - Time estimates
     9→ * - Log streaming from agents
    10→ */
    11→
    12→import chalk from 'chalk';
    13→import type { Feature, HarnessConfig } from '../types.js';
    14→import type { Orchestrator } from '../orchestrator/Orchestrator.js';
    15→
    16→export interface DashboardOptions {
    17→  /** Enable live refresh (clears terminal) */
    18→  liveRefresh: boolean;
    19→  /** Refresh interval in ms */
    20→  refreshInterval: number;
    21→  /** Maximum log lines to keep */
    22→  maxLogLines: number;
    23→  /** Show cost estimates */
    24→  showCosts: boolean;
    25→}
    26→
    27→interface AgentState {
    28→  id: string;
    29→  taskId: string;
    30→  startedAt: Date;
    31→  status: 'running' | 'completed' | 'failed';
    32→  lastOutput?: string;
    33→}
    34→
    35→interface TaskState {
    36→  id: string;
    37→  description: string;
    38→  status: 'pending' | 'ready' | 'running' | 'completed' | 'failed';
    39→  startedAt?: Date;
    40→  completedAt?: Date;
    41→  error?: string;
    42→  agentId?: string;
    43→}
    44→
    45→interface CostEstimate {
    46→  inputTokens: number;
    47→  outputTokens: number;
    48→  totalCost: number;
    49→}
    50→
    51→const DEFAULT_OPTIONS: DashboardOptions = {
    52→  liveRefresh: true,
    53→  refreshInterval: 500,
    54→  maxLogLines: 10,
    55→  showCosts: true,
    56→};
    57→
    58→// Estimated costs per model per 1M tokens (Dec 2024 pricing)
    59→const MODEL_COSTS = {
    60→  haiku: { input: 0.25, output: 1.25 },
    61→  sonnet: { input: 3.0, output: 15.0 },
    62→  opus: { input: 15.0, output: 75.0 },
    63→} as const;
    64→
    65→export class Dashboard {
    66→  private options: DashboardOptions;
    67→  private agents: Map<string, AgentState> = new Map();
    68→  private tasks: Map<string, TaskState> = new Map();
    69→  private logs: string[] = [];
    70→  private startTime?: Date;
    71→  private endTime?: Date;
    72→  private refreshTimer?: ReturnType<typeof setInterval>;
    73→  private costs: CostEstimate = { inputTokens: 0, outputTokens: 0, totalCost: 0 };
    74→  private model: 'haiku' | 'sonnet' | 'opus' = 'sonnet';
    75→  private isRunning = false;
    76→
    77→  constructor(
    78→    private config: HarnessConfig,
    79→    options: Partial<DashboardOptions> = {}
    80→  ) {
    81→    this.options = { ...DEFAULT_OPTIONS, ...options };
    82→
    83→    // Initialize task states from config
    84→    for (const feature of config.features) {
    85→      this.tasks.set(feature.id, {
    86→        id: feature.id,
    87→        description: feature.description,
    88→        status: feature.passes ? 'completed' : 'pending',
    89→      });
    90→    }
    91→  }
    92→
    93→  /**
    94→   * Attach to an orchestrator and listen for events
    95→   */
    96→  attach(orchestrator: Orchestrator): void {
    97→    orchestrator.on('started', () => {
    98→      this.startTime = new Date();
    99→      this.isRunning = true;
   100→      this.addLog('🚀 Orchestration started');
   101→      if (this.options.liveRefresh) {
   102→        this.startRefresh();
   103→      }
   104→    });
   105→
   106→    orchestrator.on('taskDispatched', ({ taskId, feature }) => {
   107→      this.updateTask(taskId, { status: 'running', startedAt: new Date() });
   108→      this.addLog(`▶ ${chalk.blue(taskId)}: ${feature.description}`);
   109→    });
   110→
   111→    orchestrator.on('taskStarted', ({ agentId, taskId }) => {
   112→      this.agents.set(agentId, {
   113→        id: agentId,
   114→        taskId,
   115→        startedAt: new Date(),
   116→        status: 'running',
   117→      });
   118→      this.updateTask(taskId, { agentId });
   119→    });
   120→
   121→    orchestrator.on('taskOutput', ({ agentId, taskId, text }) => {
   122→      const agent = this.agents.get(agentId);
   123→      if (agent) {
   124→        agent.lastOutput = text.slice(0, 100);
   125→      }
   126→      // Estimate tokens from output (rough: 1 token ~ 4 chars)
   127→      this.addOutputTokens(Math.ceil(text.length / 4));
   128→    });
   129→
   130→    orchestrator.on('taskSucceeded', ({ taskId }) => {
   131→      this.updateTask(taskId, { status: 'completed', completedAt: new Date() });
   132→      this.addLog(`${chalk.green('✓')} ${chalk.green(taskId)} completed`);
   133→    });
   134→
   135→    orchestrator.on('taskFailed', ({ taskId, error }) => {
   136→      this.updateTask(taskId, { status: 'failed', error, completedAt: new Date() });
   137→      this.addLog(`${chalk.red('✗')} ${chalk.red(taskId)}: ${error}`);
   138→    });
   139→
   140→    orchestrator.on('taskKilled', ({ agentId, taskId, reason }) => {
   141→      const agent = this.agents.get(agentId);
   142→      if (agent) {
   143→        agent.status = 'failed';
   144→      }
   145→      this.addLog(`${chalk.yellow('⚠')} ${taskId} killed: ${reason}`);
   146→    });
   147→
   148→    orchestrator.on('deadlock', ({ pending }) => {
   149→      this.addLog(`${chalk.red('⚠️')} Deadlock detected! ${pending} tasks stuck.`);
   150→    });
   151→
   152→    orchestrator.on('shutdown', ({ signal }) => {
   153→      this.addLog(`${chalk.yellow('⚠️')} Received ${signal}, shutting down...`);
   154→    });
   155→
   156→    orchestrator.on('finished', ({ completed, failed }) => {
   157→      this.endTime = new Date();
   158→      this.isRunning = false;
   159→      this.stopRefresh();
   160→      this.addLog(`🏁 Finished: ${completed} completed, ${failed} failed`);
   161→      this.render();
   162→    });
   163→  }
   164→
   165→  /**
   166→   * Set the model for cost estimation
   167→   */
