/**
 * Git Manager for Feature Branches
 *
 * Manages git operations for feature isolation:
 * - Create feature branches
 * - Merge successful features
 * - Rollback failed features
 * - Handle conflicts
 */

import { spawn, execSync } from 'node:child_process';
import { EventEmitter } from 'node:events';

export interface GitConfig {
  /** Working directory for git operations */
  cwd: string;
  /** Branch prefix for feature branches */
  branchPrefix: string;
  /** Main branch name */
  mainBranch: string;
  /** Whether to auto-stash before operations */
  autoStash: boolean;
}

export interface BranchInfo {
  name: string;
  featureId: string;
  createdAt: Date;
  isMerged: boolean;
}

export interface MergeResult {
  success: boolean;
  conflictFiles?: string[];
  error?: string;
}

const DEFAULT_CONFIG: GitConfig = {
  cwd: process.cwd(),
  branchPrefix: 'feature/',
  mainBranch: 'main',
  autoStash: true,
};

export class GitManager extends EventEmitter {
  private config: GitConfig;
  private stashCreated = false;

  constructor(config: Partial<GitConfig> = {}) {
    super();
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Execute a git command and return output
   */
  private exec(args: string[]): string {
    try {
      const result = execSync(`git ${args.join(' ')}`, {
        cwd: this.config.cwd,
        encoding: 'utf-8',
        stdio: ['pipe', 'pipe', 'pipe'],
      });
      return result.trim();
    } catch (error: any) {
      throw new Error(`Git command failed: git ${args.join(' ')}\n${error.stderr || error.message}`);
    }
  }

  /**
   * Check if the working directory is a git repository
   */
  isGitRepo(): boolean {
    try {
      this.exec(['rev-parse', '--is-inside-work-tree']);
      return true;
    } catch {
      return false;
    }
  }

  /**
   * Get the current branch name
   */
  getCurrentBranch(): string {
    return this.exec(['rev-parse', '--abbrev-ref', 'HEAD']);
  }

  /**
   * Check if there are uncommitted changes
   */
  hasUncommittedChanges(): boolean {
    const status = this.exec(['status', '--porcelain']);
    return status.length > 0;
  }

  /**
   * Create a stash if there are uncommitted changes
   */
  stashIfNeeded(): boolean {
    if (this.config.autoStash && this.hasUncommittedChanges()) {
      this.exec(['stash', 'push', '-m', 'harness-orchestrator-auto-stash']);
      this.stashCreated = true;
      this.emit('stashed');
      return true;
    }
    return false;
  }

  /**
   * Pop the stash if one was created
   */
  popStashIfNeeded(): void {
    if (this.stashCreated) {
      try {
        this.exec(['stash', 'pop']);
        this.stashCreated = false;
        this.emit('unstashed');
      } catch (error) {
        this.emit('stash-conflict', { error });
      }
    }
  }

  /**
   * Get the branch name for a feature
   */
  getBranchName(featureId: string): string {
    return `${this.config.branchPrefix}${featureId.toLowerCase()}`;
  }

  /**
   * Check if a branch exists
   */
  branchExists(branchName: string): boolean {
    try {
      this.exec(['rev-parse', '--verify', branchName]);
      return true;
    } catch {
      return false;
    }
  }

  /**
   * Create a new branch for a feature
   */
  createFeatureBranch(featureId: string): string {
    const branchName = this.getBranchName(featureId);

    if (this.branchExists(branchName)) {
      throw new Error(`Branch ${branchName} already exists`);
    }

    // Ensure we're on main branch
    const currentBranch = this.getCurrentBranch();
    if (currentBranch !== this.config.mainBranch) {
      this.exec(['checkout', this.config.mainBranch]);
    }

    // Create and checkout the new branch
    this.exec(['checkout', '-b', branchName]);
    this.emit('branch-created', { featureId, branchName });

    return branchName;
  }

  /**
   * Checkout an existing branch
   */
  checkoutBranch(branchName: string): void {
    this.stashIfNeeded();
    this.exec(['checkout', branchName]);
    this.emit('branch-checkout', { branchName });
  }

  /**
   * Get list of feature branches
   */
  listFeatureBranches(): BranchInfo[] {
    const prefix = this.config.branchPrefix;
    const branches = this.exec(['branch', '--list', `${prefix}*`])
      .split('\n')
      .map(b => b.trim().replace(/^\*\s*/, ''))
      .filter(b => b.length > 0);

    return branches.map(name => {
      const featureId = name.replace(prefix, '').toUpperCase();
      return {
        name,
        featureId,
        createdAt: new Date(), // Would need git log to get actual date
        isMerged: this.isBranchMerged(name),
      };
    });
  }

  /**
   * Check if a branch is merged into main
   */
  isBranchMerged(branchName: string): boolean {
    try {
      const merged = this.exec(['branch', '--merged', this.config.mainBranch]);
      return merged.split('\n').some(b => b.trim() === branchName);
    } catch {
      return false;
    }
  }

  /**
   * Merge a feature branch into main
   */
  mergeFeatureBranch(featureId: string, commitMessage?: string): MergeResult {
    const branchName = this.getBranchName(featureId);

    if (!this.branchExists(branchName)) {
      return { success: false, error: `Branch ${branchName} does not exist` };
    }

    try {
      // Switch to main
      this.exec(['checkout', this.config.mainBranch]);

      // Try to merge
      const message = commitMessage || `Merge feature ${featureId}`;
      this.exec(['merge', branchName, '-m', message]);

      this.emit('branch-merged', { featureId, branchName });
      return { success: true };
    } catch (error: any) {
      // Check for merge conflicts
      const status = this.exec(['status', '--porcelain']);
      const conflictFiles = status
        .split('\n')
        .filter(line => line.startsWith('UU') || line.startsWith('AA'))
        .map(line => line.slice(3));

      if (conflictFiles.length > 0) {
        // Abort the merge
        this.exec(['merge', '--abort']);
        return {
          success: false,
          conflictFiles,
          error: 'Merge conflicts detected',
        };
      }

      return { success: false, error: error.message };
    }
  }

  /**
   * Rollback a feature by deleting its branch
   */
  rollbackFeature(featureId: string, deleteRemote = false): void {
    const branchName = this.getBranchName(featureId);

    // Make sure we're not on the branch we're deleting
    if (this.getCurrentBranch() === branchName) {
      this.exec(['checkout', this.config.mainBranch]);
    }

    // Delete local branch
    if (this.branchExists(branchName)) {
      this.exec(['branch', '-D', branchName]);
      this.emit('branch-deleted', { featureId, branchName });
    }

    // Optionally delete remote branch
    if (deleteRemote) {
      try {
        this.exec(['push', 'origin', '--delete', branchName]);
        this.emit('remote-branch-deleted', { featureId, branchName });
      } catch {
        // Remote branch might not exist
      }
    }
  }

  /**
   * Get the last commit message on a branch
   */
  getLastCommitMessage(branchName?: string): string {
    const branch = branchName || 'HEAD';
    return this.exec(['log', '-1', '--format=%B', branch]).trim();
  }

  /**
   * Get the diff between a feature branch and main
   */
  getFeatureDiff(featureId: string): string {
    const branchName = this.getBranchName(featureId);
    return this.exec(['diff', this.config.mainBranch, branchName]);
  }

  /**
   * Create a snapshot commit
   */
  createSnapshot(message: string): string {
    if (!this.hasUncommittedChanges()) {
      return this.exec(['rev-parse', 'HEAD']);
    }

    this.exec(['add', '-A']);
    this.exec(['commit', '-m', message]);
    return this.exec(['rev-parse', 'HEAD']);
  }

  /**
   * Reset to a specific commit
   */
  resetToCommit(commitHash: string, hard = true): void {
    const mode = hard ? '--hard' : '--soft';
    this.exec(['reset', mode, commitHash]);
    this.emit('reset', { commitHash, hard });
  }

  /**
   * Get status summary
   */
  getStatus(): {
    branch: string;
    isClean: boolean;
    ahead: number;
    behind: number;
  } {
    const branch = this.getCurrentBranch();
    const isClean = !this.hasUncommittedChanges();

    let ahead = 0;
    let behind = 0;

    try {
      const status = this.exec(['status', '-sb']);
      const match = status.match(/\[ahead (\d+)(?:, behind (\d+))?\]|\[behind (\d+)\]/);
      if (match) {
        ahead = parseInt(match[1] || '0', 10);
        behind = parseInt(match[2] || match[3] || '0', 10);
      }
    } catch {
      // Ignore errors getting ahead/behind
    }

    return { branch, isClean, ahead, behind };
  }
}

