/**
 * Main Orchestrator
 *
 * Central coordination logic that ties together all components:
 * - DependencyGraph: Task relationships
 * - TaskScheduler: Ready queue and priority
 * - AgentPool: Claude process management
 * - StateManager: Persistent state
 */

import { EventEmitter } from 'node:events';
import type { HarnessConfig, Feature, ModelType } from '../types.js';
import { DependencyGraph } from '../graph/DependencyGraph.js';
import { TaskScheduler } from '../scheduler/TaskScheduler.js';
import { AgentPool } from '../agents/AgentPool.js';
import { StateManager } from '../state/StateManager.js';
import type { AgentResult } from '../agents/ClaudeAgent.js';

export interface OrchestratorOptions {
  maxAgents: number;
  model: ModelType;
  cwd?: string;
  timeout?: number;
}

export interface TaskEvent {
  taskId: string;
  agentId?: string;
  result?: AgentResult;
  error?: string;
}

export class Orchestrator extends EventEmitter {
  private graph: DependencyGraph;
  private scheduler: TaskScheduler;
  private agentPool: AgentPool;
  private stateManager: StateManager;
  private isRunning = false;
  private isShuttingDown = false;
  private activePromises: Map<string, Promise<void>> = new Map();

  constructor(
    private featuresPath: string,
    private options: OrchestratorOptions
  ) {
    super();
    this.stateManager = new StateManager(featuresPath);
    const config = this.stateManager.load();

    this.graph = new DependencyGraph(config);
    this.scheduler = new TaskScheduler(this.graph, options.maxAgents);
    this.agentPool = new AgentPool(options.maxAgents, {
      model: options.model,
      cwd: options.cwd,
      timeout: options.timeout,
    });

    this.setupAgentPoolEvents();
    this.setupSignalHandlers();
  }

  /**
   * Forward agent pool events
   */
  private setupAgentPoolEvents(): void {
    this.agentPool.on('spawn', (event) => {
      this.emit('taskStarted', event);
    });

    this.agentPool.on('output', (event) => {
      this.emit('taskOutput', event);
    });

    this.agentPool.on('error', (event) => {
      this.emit('taskError', event);
    });

    this.agentPool.on('complete', (event) => {
      this.emit('taskComplete', event);
    });

    this.agentPool.on('killed', (event) => {
      this.emit('taskKilled', event);
    });
  }

  /**
   * Setup graceful shutdown handlers
   */
  private setupSignalHandlers(): void {
    const shutdown = async (signal: string) => {
      if (this.isShuttingDown) return;
      this.isShuttingDown = true;

      this.emit('shutdown', { signal });

      // Kill all agents
      this.agentPool.killAll(`Received ${signal}`);

      // Wait for active promises to resolve
      if (this.activePromises.size > 0) {
        await Promise.allSettled([...this.activePromises.values()]);
      }

      this.isRunning = false;
      this.emit('stopped', { signal });
    };

    process.on('SIGINT', () => shutdown('SIGINT'));
    process.on('SIGTERM', () => shutdown('SIGTERM'));
  }

  /**
   * Initialize and validate the graph
   */
  initialize(): { valid: boolean; error?: string } {
    // Detect cycles (would cause deadlock)
    const cycle = this.graph.detectCycles();
    if (cycle) {
      return {
        valid: false,
        error: `Cycle detected: ${cycle.join(' → ')}`,
      };
    }

    return { valid: true };
  }

  /**
   * Run the main orchestration loop
   */
  async run(): Promise<{ completed: number; failed: number }> {
    const validation = this.initialize();
    if (!validation.valid) {
      throw new Error(validation.error);
    }

    this.isRunning = true;
    this.emit('started');

    let completed = 0;
    let failed = 0;

    // Create snapshot before starting
    this.stateManager.createSnapshot('pre-orchestration');

    while (this.isRunning && !this.scheduler.isComplete()) {
      if (this.isShuttingDown) break;

      // Get next batch of tasks
      const tasks = this.scheduler.getNextTasks();

      if (tasks.length === 0) {
        // Check for deadlock
        if (this.scheduler.getRunningCount() === 0) {
          const summary = this.scheduler.getSummary();
          if (summary.pending > 0) {
            this.emit('deadlock', { pending: summary.pending });
            break;
          }
        }

        // Wait a bit before checking again
        await this.sleep(1000);
        continue;
      }

      // Dispatch tasks in parallel
      const promises = tasks.map((task) => this.executeTask(task));

      // Wait for any task to complete
      const results = await Promise.allSettled(promises);

      // Process results
      for (const result of results) {
        if (result.status === 'fulfilled') {
          if (result.value.success) {
            completed++;
          } else {
            failed++;
          }
        } else {
          failed++;
        }
      }

      // Refresh ready queue to unlock dependents
      this.scheduler.refreshReadyQueue();
    }

    this.isRunning = false;
    this.emit('finished', { completed, failed });

    return { completed, failed };
  }

  /**
   * Execute a single task
   */
  private async executeTask(feature: Feature): Promise<{ success: boolean }> {
    const taskId = feature.id;

    try {
      this.scheduler.startTask(taskId, `agent-${taskId}`);
      this.emit('taskDispatched', { taskId, feature });

      const result = await this.agentPool.spawnForFeature(feature, {
        model: this.options.model,
        cwd: this.options.cwd,
        timeout: this.options.timeout,
      });

      if (result.success) {
        // Update persistent state
        await this.stateManager.markComplete(taskId);
        this.scheduler.completeTask(taskId);
        this.emit('taskSucceeded', { taskId, result });
        return { success: true };
      } else {
        this.scheduler.failTask(taskId, result.error || 'Unknown error');
        this.emit('taskFailed', { taskId, error: result.error });
        return { success: false };
      }
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      this.scheduler.failTask(taskId, errorMsg);
      this.emit('taskFailed', { taskId, error: errorMsg });
      return { success: false };
    }
  }

  /**
   * Get current status
   */
  getStatus(): {
    running: boolean;
    summary: { pending: number; running: number; completed: number; failed: number };
    activeAgents: number;
  } {
    return {
      running: this.isRunning,
      summary: this.scheduler.getSummary(),
      activeAgents: this.agentPool.getActiveCount(),
    };
  }

  /**
   * Stop the orchestrator gracefully
   */
  async stop(reason?: string): Promise<void> {
    this.isShuttingDown = true;
    this.agentPool.killAll(reason || 'Manual stop');
    this.isRunning = false;
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

